import React from 'react';
import { NavLink, useNavigate } from 'react-router-dom';
import { FiGrid, FiCalendar, FiFileText, FiHome, FiSettings, FiLogOut } from 'react-icons/fi';
import { useAuth } from '../../context/AuthContext';

const Sidebar = () => {
	const { logout, isAdmin } = useAuth();
	const navigate = useNavigate();

	const handleLogout = () => {
		logout();
		navigate('/login');
	};

	return (
		<aside className="sidebar">
			<div className="sidebar-top">
				<div className="sidebar-brand">
					<div className="sidebar-brand-badge" aria-hidden="true">
						V
					</div>
					<div className="sidebar-brand-text">
						<div className="sidebar-brand-title">Verdant Hub</div>
						<div className="sidebar-brand-subtitle">Smart Campus Management</div>
					</div>
				</div>

				<nav className="sidebar-nav">
					<NavLink to={isAdmin() ? '/admin/dashboard' : '/dashboard'} className={({ isActive }) => `sidebar-link ${isActive ? 'active' : ''}`}>
						<FiGrid />
						<span>Dashboard</span>
					</NavLink>

					<NavLink to="/bookings" className={({ isActive }) => `sidebar-link ${isActive ? 'active' : ''}`}>
						<FiCalendar />
						<span>Bookings</span>
					</NavLink>

					{isAdmin() && (
						<NavLink to="/admin/bookings" className={({ isActive }) => `sidebar-link ${isActive ? 'active' : ''}`}>
							<FiFileText />
							<span>Requests</span>
						</NavLink>
					)}

					<NavLink to="/rooms" className={({ isActive }) => `sidebar-link ${isActive ? 'active' : ''}`}>
						<FiHome />
						<span>Rooms</span>
					</NavLink>

					<button type="button" className="sidebar-link sidebar-link--button">
						<FiSettings />
						<span>Settings</span>
					</button>
				</nav>
			</div>

			<div className="sidebar-bottom">
				<div className="sidebar-status">
					<div className="sidebar-status-title">Campus Status</div>
					<div className="sidebar-status-row">
						<span className="sidebar-status-dot" aria-hidden="true" />
						<span className="sidebar-status-text">All systems optimal</span>
					</div>
				</div>

				<button type="button" className="sidebar-footer-link" onClick={handleLogout}>
					<FiLogOut />
					<span>Logout</span>
				</button>
			</div>
		</aside>
	);
};

export default Sidebar;
